const fs = require('fs');
const path = require('path');

// Prefix scheme (see ../../theme/REGISTRY.md):
//   --pal-*  org-brand ramps anchored in the IRPP style guide
//   --ext-*  our additions (mathematical neutrals, future extensions)

// 1. Define the org anchor families (IRPP style guide, see ../../theme/base_palette.md)
const orgAnchors = {
  blue: { dark: "#004667", light: "#B8C4D3" },
  teal: { dark: "#44A3A4", light: "#B5D2D3" },
  gold: { dark: "#DEAC28", light: "#F0D8A4" },
  olive: { dark: "#A0A638", light: "#D4D4A5" },
  grey: { dark: "#6D6E71", light: "#B8B6B7" },
  orange: { dark: "#D36828", light: "#EBBA97" },
  red: { dark: "#CE2129", light: "#E7A38F" },
  sage: { dark: "#77AE99", light: "#C5D8CF" },
  purple: { dark: "#55425B", light: "#BCB3BE" }
};

// 2. Define the mathematical OKLCH scales (Cleaned up)
// Cool Neutral: Navy root (H=243) at Chroma 0.008
// Warm Neutral: Orange root (H=48) at Chroma 0.010
// Pure Neutral: Achromatic scale (Chroma=0)
const steps = [900, 800, 700, 600, 500, 400, 350, 300, 250, 200, 150, 100, 50];

const lSteps = {
  900: 0.12,
  800: 0.25,
  700: 0.40,
  600: 0.52,
  500: 0.65,
  400: 0.76,
  350: 0.80,
  300: 0.85,
  250: 0.88,
  200: 0.92,
  150: 0.945,
  100: 0.97,
  50: 0.985
};

const neutralSpecs = [
  { name: "neutral-cool", hue: 243, chromas: [0.008] },
  { name: "neutral-warm", hue: 48, chromas: [0.01] },
  { name: "neutral-pure", hue: 0, chromas: [0] } // Pure white-to-black scale (chroma = 0)
];

const mathFamilies = {};
neutralSpecs.forEach(spec => {
  spec.chromas.forEach(c => {
    const isBase = c === spec.chromas[0];
    let suffix = "";
    if (!isBase) {
      suffix = `-c${c.toString().replace('.', '')}`;
    }
    const familyName = `${spec.name}${suffix}`;
    
    mathFamilies[familyName] = {};
    steps.forEach(step => {
      mathFamilies[familyName][step] = `oklch(${lSteps[step]} ${c} ${spec.hue})`;
    });
  });
});

// Explicitly bind the 50 steps since JS lookup is cleaner
mathFamilies["neutral-cool"][50] = `oklch(${lSteps[50]} 0.008 243)`;
mathFamilies["neutral-warm"][50] = `oklch(${lSteps[50]} 0.01 48)`;
mathFamilies["neutral-pure"][50] = `oklch(${lSteps[50]} 0 0)`;

let cssContent = `/* Generated by generate_palette.js - Do not edit manually */\n\n:root {\n`;

// Append Anchors
cssContent += `  /* Anchor Definitions */\n`;
for (const [name, colors] of Object.entries(orgAnchors)) {
  cssContent += `  --pal-${name}-dark: ${colors.dark};\n`;
  cssContent += `  --pal-${name}-light: ${colors.light};\n`;
}
cssContent += `\n`;

// Generate org scales with half-steps in the light range
cssContent += `  /* Interpolated Org Scales with Half-Steps */\n`;
for (const name of Object.keys(orgAnchors)) {
  cssContent += `  --pal-${name}-900: color-mix(in oklch, var(--pal-${name}-dark) 40%, black);\n`;
  cssContent += `  --pal-${name}-800: color-mix(in oklch, var(--pal-${name}-dark) 70%, black);\n`;
  cssContent += `  --pal-${name}-700: var(--pal-${name}-dark);\n`;
  cssContent += `  --pal-${name}-600: color-mix(in oklch, var(--pal-${name}-dark) 75%, var(--pal-${name}-light) 25%);\n`;
  cssContent += `  --pal-${name}-500: color-mix(in oklch, var(--pal-${name}-dark), var(--pal-${name}-light));\n`;
  cssContent += `  --pal-${name}-400: color-mix(in oklch, var(--pal-${name}-dark) 25%, var(--pal-${name}-light) 75%);\n`;
  cssContent += `  --pal-${name}-350: color-mix(in oklch, var(--pal-${name}-dark) 12.5%, var(--pal-${name}-light) 87.5%);\n`;
  cssContent += `  --pal-${name}-300: var(--pal-${name}-light);\n`;
  cssContent += `  --pal-${name}-250: color-mix(in oklch, var(--pal-${name}-light) 80%, white);\n`;
  cssContent += `  --pal-${name}-200: color-mix(in oklch, var(--pal-${name}-light) 60%, white);\n`;
  cssContent += `  --pal-${name}-150: color-mix(in oklch, var(--pal-${name}-light) 40%, white);\n`;
  cssContent += `  --pal-${name}-100: color-mix(in oklch, var(--pal-${name}-light) 20%, white);\n`;
  cssContent += `  --pal-${name}-50:  color-mix(in oklch, var(--pal-${name}-light) 10%, white);\n\n`;
}

// Generate Mathematical OKLCH Scales
cssContent += `  /* Mathematical OKLCH Scales */\n`;
for (const [name, values] of Object.entries(mathFamilies)) {
  for (const step of steps) {
    cssContent += `  --ext-${name}-${step}: ${values[step]};\n`;
  }
  cssContent += `\n`;
}

cssContent += `}\n`;

// Create the JSON metadata for the Palette Explorer portal
const paletteMetadata = [];

// Push org families
for (const name of Object.keys(orgAnchors)) {
  paletteMetadata.push({ name, steps, prefix: "pal", provenance: "org" });
}
// Push mathematical families (our extensions)
for (const name of Object.keys(mathFamilies)) {
  paletteMetadata.push({ name, steps, prefix: "ext", provenance: "extension" });
}

// Write files relative to this script's directory
const cssPath = path.join(__dirname, 'expanded_palette.css');
const jsonPath = path.join(__dirname, 'palette_data.json');

fs.writeFileSync(cssPath, cssContent, 'utf8');
fs.writeFileSync(jsonPath, JSON.stringify(paletteMetadata, null, 2), 'utf8');

console.log('Successfully generated cleaned up scales with math-pure neutrals.');
